		names[TripleStore.PRED_IDX] = unboundName(pattern.getPredicateVar());
		names[TripleStore.OBJ_IDX] = unboundName(pattern.getObjectVar());
		names[TripleStore.CONTEXT_IDX] = unboundName(pattern.getContextVar());
